664: func (s *sharedIndexInformer) AddEventHandlerWithOptions(handler ResourceEventHandler, options HandlerOptions) (ResourceEventHandlerRegistration, error) {
665: 	s.startedLock.Lock()
666: 	defer s.startedLock.Unlock()
667: 
668: 	if s.stopped {
669: 		return nil, fmt.Errorf("handler %v was not added to shared informer because it has stopped already", handler)
670: 	}
671: 
672: 	logger := ptr.Deref(options.Logger, klog.Background())
673: 	resyncPeriod := ptr.Deref(options.ResyncPeriod, s.defaultEventHandlerResyncPeriod)
674: 	if resyncPeriod > 0 {
675: 		if resyncPeriod < minimumResyncPeriod {
676: 			logger.Info("Warning: resync period is too small. Changing it to the minimum allowed value", "resyncPeriod", resyncPeriod, "minimumResyncPeriod", minimumResyncPeriod)
677: 			resyncPeriod = minimumResyncPeriod
678: 		}
679: 
680: 		if resyncPeriod < s.resyncCheckPeriod {
681: 			if s.started {
682: 				logger.Info("Warning: resync period is smaller than resync check period and the informer has already started. Changing it to the resync check period", "resyncPeriod", resyncPeriod, "resyncCheckPeriod", s.resyncCheckPeriod)
683: 
684: 				resyncPeriod = s.resyncCheckPeriod
685: 			} else {
686: 				// if the event handler's resyncPeriod is smaller than the current resyncCheckPeriod, update
687: 				// resyncCheckPeriod to match resyncPeriod and adjust the resync periods of all the listeners
688: 				// accordingly
689: 				s.resyncCheckPeriod = resyncPeriod
690: 				s.processor.resyncCheckPeriodChanged(logger, resyncPeriod)
691: 			}
692: 		}
693: 	}
694: 
695: 	listener := newProcessListener(logger, handler, resyncPeriod, determineResyncPeriod(logger, resyncPeriod, s.resyncCheckPeriod), s.clock.Now(), initialBufferSize, s.HasSynced)
696: 
697: 	if !s.started {
698: 		return s.processor.addListener(listener), nil
699: 	}
700: 
701: 	// in order to safely join, we have to
702: 	// 1. stop sending add/update/delete notifications
703: 	// 2. do a list against the store
704: 	// 3. send synthetic "Add" events to the new handler
705: 	// 4. unblock
706: 	s.blockDeltas.Lock()
707: 	defer s.blockDeltas.Unlock()
708: 
709: 	handle := s.processor.addListener(listener)
710: 	for _, item := range s.indexer.List() {
711: 		// Note that we enqueue these notifications with the lock held
712: 		// and before returning the handle. That means there is never a
713: 		// chance for anyone to call the handle's HasSynced method in a
714: 		// state when it would falsely return true (i.e., when the
715: 		// shared informer is synced but it has not observed an Add
716: 		// with isInitialList being true, nor when the thread
717: 		// processing notifications somehow goes faster than this
718: 		// thread adding them and the counter is temporarily zero).
719: 		listener.add(addNotification{newObj: item, isInInitialList: true})
720: 	}
721: 	return handle, nil
722: }
